```go
func produce(ch chan int, done chan struct{}) {
	for i := 0; i < 5; i++ {
		ch <- i
	}
	close(ch)
}
func main() {
	ch := make(chan int)
	done := make(chan struct{})
	go produce(ch, done)
	go produce(ch, done)
	for v := range ch {
		fmt.Println(v)
	}
}
```

